import{_ as e,o as l,c as a,ae as d}from"./chunks/framework.BEtfQoF7.js";const u=JSON.parse('{"title":"플랫폼 및 통합","description":"","frontmatter":{},"headers":[],"relativePath":"platforms.md","filePath":"platforms.md","lastUpdated":1776205703000}'),o={name:"platforms.md"};function c(s,t,r,i,h,n){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="플랫폼-및-통합" tabindex="-1">플랫폼 및 통합 <a class="header-anchor" href="#플랫폼-및-통합" aria-label="Permalink to &quot;플랫폼 및 통합&quot;">​</a></h1><blockquote><p>Claude Code를 실행할 위치와 연결할 대상을 선택합니다. CLI, Desktop, VS Code, JetBrains, 웹, 모바일 및 Chrome, Slack, CI/CD 등의 통합을 비교합니다.</p></blockquote><p>Claude Code는 모든 곳에서 동일한 기본 엔진을 실행하지만, 각 환경은 서로 다른 작업 방식에 맞게 조정되어 있습니다. 이 페이지는 워크플로에 맞는 적절한 플랫폼을 선택하고 이미 사용 중인 도구를 연결하는 데 도움을 줍니다.</p><h2 id="claude-code-실행-위치" tabindex="-1">Claude Code 실행 위치 <a class="header-anchor" href="#claude-code-실행-위치" aria-label="Permalink to &quot;Claude Code 실행 위치&quot;">​</a></h2><p>작업 방식과 프로젝트 위치에 따라 플랫폼을 선택하세요.</p><table tabindex="0"><thead><tr><th style="text-align:left;">플랫폼</th><th style="text-align:left;">적합한 용도</th><th style="text-align:left;">제공하는 기능</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/quickstart.html">CLI</a></td><td style="text-align:left;">터미널 워크플로, 스크립팅, 원격 서버</td><td style="text-align:left;">전체 기능 세트, <a href="/claude-code-docs-ko/headless.html">Agent SDK</a>, macOS에서 <a href="/claude-code-docs-ko/computer-use.html">computer use</a> (Pro 및 Max), 서드파티 제공자</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/desktop.html">Desktop</a></td><td style="text-align:left;">시각적 검토, 병렬 세션, 관리형 설정</td><td style="text-align:left;">diff 뷰어, 앱 미리보기, Pro 및 Max에서 <a href="/claude-code-docs-ko/desktop.html#let-claude-use-your-computer">computer use</a> 및 <a href="/claude-code-docs-ko/desktop.html#sessions-from-dispatch">Dispatch</a></td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/vs-code.html">VS Code</a></td><td style="text-align:left;">터미널로 전환하지 않고 VS Code 내에서 작업</td><td style="text-align:left;">인라인 diff, 통합 터미널, 파일 컨텍스트</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/jetbrains.html">JetBrains</a></td><td style="text-align:left;">IntelliJ, PyCharm, WebStorm 또는 기타 JetBrains IDE 내에서 작업</td><td style="text-align:left;">diff 뷰어, 선택 공유, 터미널 세션</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹</a></td><td style="text-align:left;">많은 조작이 필요 없는 장시간 작업이거나 오프라인일 때도 계속되어야 하는 작업</td><td style="text-align:left;">Anthropic 관리 클라우드, 연결 해제 후에도 계속 실행</td></tr><tr><td style="text-align:left;">모바일</td><td style="text-align:left;">컴퓨터에서 떨어져 있을 때 작업 시작 및 모니터링</td><td style="text-align:left;">iOS 및 Android용 Claude 앱의 클라우드 세션, 로컬 세션을 위한 <a href="/claude-code-docs-ko/remote-control.html">Remote Control</a>, Pro 및 Max에서 Desktop으로 <a href="/claude-code-docs-ko/desktop.html#sessions-from-dispatch">Dispatch</a></td></tr></tbody></table><p>CLI는 터미널 네이티브 작업에 가장 완전한 환경입니다: 스크립팅, 서드파티 제공자, Agent SDK는 CLI 전용입니다. Desktop과 IDE 확장은 일부 CLI 전용 기능을 시각적 검토와 더 긴밀한 에디터 통합으로 대체합니다. 웹은 Anthropic 클라우드에서 실행되므로 연결 해제 후에도 작업이 계속됩니다. 모바일은 동일한 클라우드 세션이나 Remote Control을 통한 로컬 세션으로의 씬 클라이언트이며, Dispatch로 Desktop에 작업을 보낼 수 있습니다.</p><p>동일한 프로젝트에서 여러 환경을 혼합할 수 있습니다. 설정, 프로젝트 메모리, MCP 서버는 로컬 환경 간에 공유됩니다.</p><h2 id="도구-연결" tabindex="-1">도구 연결 <a class="header-anchor" href="#도구-연결" aria-label="Permalink to &quot;도구 연결&quot;">​</a></h2><p>통합을 통해 Claude가 코드베이스 외부의 서비스와 작업할 수 있습니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;">통합</th><th style="text-align:left;">기능</th><th style="text-align:left;">용도</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/chrome.html">Chrome</a></td><td style="text-align:left;">로그인된 세션으로 브라우저를 제어합니다</td><td style="text-align:left;">웹 앱 테스트, 양식 작성, API 없는 사이트 자동화</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/github-actions.html">GitHub Actions</a></td><td style="text-align:left;">CI 파이프라인에서 Claude를 실행합니다</td><td style="text-align:left;">자동 PR 리뷰, 이슈 분류, 예약된 유지보수</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/gitlab-ci-cd.html">GitLab CI/CD</a></td><td style="text-align:left;">GitLab용 GitHub Actions와 동일</td><td style="text-align:left;">GitLab에서의 CI 기반 자동화</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/code-review.html">Code Review</a></td><td style="text-align:left;">모든 PR을 자동으로 리뷰합니다</td><td style="text-align:left;">사람이 리뷰하기 전에 버그 발견</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/slack.html">Slack</a></td><td style="text-align:left;">채널에서 <code>@Claude</code> 멘션에 응답합니다</td><td style="text-align:left;">팀 채팅에서 버그 리포트를 풀 리퀘스트로 전환</td></tr></tbody></table><p>여기에 나열되지 않은 통합의 경우 <a href="/claude-code-docs-ko/mcp.html">MCP 서버</a>와 <a href="/claude-code-docs-ko/desktop.html#connect-external-tools">커넥터</a>를 사용하여 Linear, Notion, Google Drive 또는 자체 내부 API 등 거의 모든 것을 연결할 수 있습니다.</p><h2 id="터미널에서-떨어져-있을-때-작업하기" tabindex="-1">터미널에서 떨어져 있을 때 작업하기 <a class="header-anchor" href="#터미널에서-떨어져-있을-때-작업하기" aria-label="Permalink to &quot;터미널에서 떨어져 있을 때 작업하기&quot;">​</a></h2><p>Claude Code는 터미널에 없을 때 작업할 수 있는 여러 방법을 제공합니다. 작업을 트리거하는 것, Claude가 실행되는 위치, 설정에 필요한 정도가 다릅니다.</p><table tabindex="0"><thead><tr><th style="text-align:left;"></th><th style="text-align:left;">트리거</th><th style="text-align:left;">Claude 실행 위치</th><th style="text-align:left;">설정</th><th style="text-align:left;">적합한 용도</th></tr></thead><tbody><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/desktop.html#sessions-from-dispatch">Dispatch</a></td><td style="text-align:left;">Claude 모바일 앱에서 작업 메시지 전송</td><td style="text-align:left;">사용자의 컴퓨터 (Desktop)</td><td style="text-align:left;"><a href="https://support.claude.com/en/articles/13947068" target="_blank" rel="noreferrer">모바일 앱과 Desktop 페어링</a></td><td style="text-align:left;">자리를 비운 동안 작업 위임, 최소한의 설정</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/remote-control.html">Remote Control</a></td><td style="text-align:left;"><a href="https://claude.ai/code" target="_blank" rel="noreferrer">claude.ai/code</a> 또는 Claude 모바일 앱에서 실행 중인 세션 제어</td><td style="text-align:left;">사용자의 컴퓨터 (CLI 또는 VS Code)</td><td style="text-align:left;"><code>claude remote-control</code> 실행</td><td style="text-align:left;">다른 기기에서 진행 중인 작업 조종</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/channels.html">Channels</a></td><td style="text-align:left;">Telegram이나 Discord 같은 채팅 앱, 또는 자체 서버에서의 푸시 이벤트</td><td style="text-align:left;">사용자의 컴퓨터 (CLI)</td><td style="text-align:left;"><a href="/claude-code-docs-ko/channels.html#quickstart">채널 플러그인 설치</a> 또는 <a href="/claude-code-docs-ko/channels-reference.html">직접 구축</a></td><td style="text-align:left;">CI 실패나 채팅 메시지 같은 외부 이벤트에 반응</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/slack.html">Slack</a></td><td style="text-align:left;">팀 채널에서 <code>@Claude</code> 멘션</td><td style="text-align:left;">Anthropic 클라우드</td><td style="text-align:left;"><a href="/claude-code-docs-ko/claude-code-on-the-web.html">Claude Code on the web</a> 활성화와 함께 <a href="/claude-code-docs-ko/slack.html#setting-up-claude-code-in-slack">Slack 앱 설치</a></td><td style="text-align:left;">팀 채팅에서 PR 및 리뷰</td></tr><tr><td style="text-align:left;"><a href="/claude-code-docs-ko/scheduled-tasks.html">예약 작업</a></td><td style="text-align:left;">일정 설정</td><td style="text-align:left;"><a href="/claude-code-docs-ko/scheduled-tasks.html">CLI</a>, <a href="/claude-code-docs-ko/desktop-scheduled-tasks.html">Desktop</a>, 또는 <a href="/claude-code-docs-ko/web-scheduled-tasks.html">클라우드</a></td><td style="text-align:left;">빈도 선택</td><td style="text-align:left;">일일 리뷰와 같은 반복 자동화</td></tr></tbody></table><p>어디서 시작해야 할지 모르겠다면 <a href="/claude-code-docs-ko/quickstart.html">CLI를 설치</a>하고 프로젝트 디렉토리에서 실행하세요. 터미널을 사용하고 싶지 않다면 <a href="/claude-code-docs-ko/desktop-quickstart.html">Desktop</a>이 그래픽 인터페이스로 동일한 엔진을 제공합니다.</p><h2 id="관련-리소스" tabindex="-1">관련 리소스 <a class="header-anchor" href="#관련-리소스" aria-label="Permalink to &quot;관련 리소스&quot;">​</a></h2><h3 id="플랫폼" tabindex="-1">플랫폼 <a class="header-anchor" href="#플랫폼" aria-label="Permalink to &quot;플랫폼&quot;">​</a></h3><ul><li><a href="/claude-code-docs-ko/quickstart.html">CLI 빠른 시작</a>: 터미널에서 설치하고 첫 번째 명령어 실행</li><li><a href="/claude-code-docs-ko/desktop.html">Desktop</a>: 시각적 diff 검토, 병렬 세션, computer use, Dispatch</li><li><a href="/claude-code-docs-ko/vs-code.html">VS Code</a>: 에디터 내부의 Claude Code 확장</li><li><a href="/claude-code-docs-ko/jetbrains.html">JetBrains</a>: IntelliJ, PyCharm 및 기타 JetBrains IDE용 확장</li><li><a href="/claude-code-docs-ko/claude-code-on-the-web.html">Claude Code on the web</a>: 연결 해제 시에도 계속 실행되는 클라우드 세션</li><li>모바일: 컴퓨터에서 떨어져 있을 때 작업을 시작하고 모니터링하기 위한 <a href="https://apps.apple.com/us/app/claude-by-anthropic/id6473753684" target="_blank" rel="noreferrer">iOS</a> 및 <a href="https://play.google.com/store/apps/details?id=com.anthropic.claude" target="_blank" rel="noreferrer">Android</a>용 Claude 앱</li></ul><h3 id="통합" tabindex="-1">통합 <a class="header-anchor" href="#통합" aria-label="Permalink to &quot;통합&quot;">​</a></h3><ul><li><a href="/claude-code-docs-ko/chrome.html">Chrome</a>: 로그인된 세션으로 브라우저 작업 자동화</li><li><a href="/claude-code-docs-ko/computer-use.html">Computer use</a>: macOS에서 Claude가 앱을 열고 화면을 제어하도록 허용</li><li><a href="/claude-code-docs-ko/github-actions.html">GitHub Actions</a>: CI 파이프라인에서 Claude 실행</li><li><a href="/claude-code-docs-ko/gitlab-ci-cd.html">GitLab CI/CD</a>: GitLab용 동일 기능</li><li><a href="/claude-code-docs-ko/code-review.html">Code Review</a>: 모든 풀 리퀘스트에 대한 자동 리뷰</li><li><a href="/claude-code-docs-ko/slack.html">Slack</a>: 팀 채팅에서 작업을 보내고 PR을 받기</li></ul><h3 id="원격-접근" tabindex="-1">원격 접근 <a class="header-anchor" href="#원격-접근" aria-label="Permalink to &quot;원격 접근&quot;">​</a></h3><ul><li><a href="/claude-code-docs-ko/desktop.html#sessions-from-dispatch">Dispatch</a>: 폰에서 작업 메시지를 보내면 Desktop 세션을 생성할 수 있습니다</li><li><a href="/claude-code-docs-ko/remote-control.html">Remote Control</a>: 폰이나 브라우저에서 실행 중인 세션을 제어</li><li><a href="/claude-code-docs-ko/channels.html">Channels</a>: 채팅 앱이나 자체 서버에서 세션으로 이벤트를 푸시</li><li><a href="/claude-code-docs-ko/scheduled-tasks.html">예약 작업</a>: 반복 일정으로 프롬프트 실행</li></ul>',23)])])}const k=e(o,[["render",c]]);export{u as __pageData,k as default};
